def format_schedule(class_name: str, day: str) -> str:
    """Dars jadvalini chiroyli matn sifatida qaytaradi"""
    if class_name not in SCHEDULE or day not in SCHEDULE.get(class_name, {}):
        return None

    lessons = SCHEDULE[class_name][day]
    lines = [f"📚 <b>{class_name} sinfi — {day}</b>\n"]

    for i, l in enumerate(lessons, 1):
        lines.append(f"<b>{i}.</b> {l['subject']}\n   🕐 <code>{l['time']}</code>")

    total_mins = sum(
        (int(l['time'].split('-')[1].split(':')[0]) * 60 + int(l['time'].split('-')[1].split(':')[1])) -
        (int(l['time'].split('-')[0].split(':')[0]) * 60 + int(l['time'].split('-')[0].split(':')[1]))
        for l in lessons
    )
    lines.append(f"\n📊 Jami: <b>{len(lessons)} ta dars</b> · ⏱ <b>{total_mins // 60}h {total_mins % 60}min</b>")
    lines.append(f"🏁 {lessons[0]['time'].split('-')[0]} – {lessons[-1]['time'].split('-')[1]}")

    return "\n".join(lines)
